export const meta = {
  name: 'review-pr33',
  description: 'Deep multi-agent review of PR #33 (issue_download_attachment): API conformance, standards, security, design, tests, real lint/type/test run',
  phases: [
    { title: 'Review', detail: 'parallel finders across dimensions + real tooling run' },
    { title: 'Verify', detail: 'adversarially verify each finding' },
  ],
}

const DIFF = '/tmp/pr33.diff'

const FINDINGS_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['findings'],
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['title', 'severity', 'category', 'location', 'description', 'evidence', 'recommendation', 'confidence'],
        properties: {
          title: { type: 'string', description: 'Short headline of the issue' },
          severity: { type: 'string', enum: ['blocker', 'major', 'minor', 'nit'] },
          category: { type: 'string', description: 'e.g. api-conformance, standards, security, design, tests, tooling' },
          location: { type: 'string', description: 'file:line or file, pointing at the code in question' },
          description: { type: 'string', description: 'What is wrong and why it matters' },
          evidence: { type: 'string', description: 'Concrete proof: code snippet, doc quote/URL, or command output' },
          recommendation: { type: 'string', description: 'Concrete fix' },
          confidence: { type: 'string', enum: ['high', 'medium', 'low'] },
        },
      },
    },
  },
}

const VERDICT_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['verdict', 'reasoning', 'adjusted_severity'],
  properties: {
    verdict: { type: 'string', enum: ['confirmed', 'refuted', 'uncertain'] },
    reasoning: { type: 'string', description: 'Why the finding holds or fails, grounded in code/docs' },
    adjusted_severity: { type: 'string', enum: ['blocker', 'major', 'minor', 'nit', 'invalid'] },
  },
}

const PROJECT_CONTEXT = `
PROJECT CONTEXT (MCP Yandex Tracker server):
- Layered architecture: protocol (mcp_tracker/tracker/proto/) -> HTTP client (mcp_tracker/tracker/custom/client.py) -> caching wrapper (mcp_tracker/tracker/caching/client.py) -> MCP tools (mcp_tracker/mcp/tools/).
- HTTP client uses a single aiohttp ClientSession with base_url=https://api.tracker.yandex.net/ ; methods call self._session.get("v3/...", headers=await self._build_headers(auth)).
- Pydantic models for Tracker entities inherit BaseTrackerEntity (see CLAUDE.md). IssueAttachment already exposes a 'mimetype' field from the API metadata.
- Read tools live in mcp_tracker/mcp/tools/issue_read.py. Existing read tools follow naming 'issue_get_*' (issue_get, issue_get_attachments, issue_get_comments, ...). PR adds a tool named 'issue_download_attachment'.
- 'task' runs format+lint(ruff)+type(mypy/pyright)+tests and is REQUIRED before commits. CLAUDE.md has detailed testing rules.
- The diff under review is saved at ${DIFF}. The full repo is checked out in the cwd on branch main (base). Read actual repo files for the pre-existing code that the diff builds on.
`

phase('Review')

const finders = [
  {
    key: 'api-conformance',
    prompt: `You are reviewing PR #33 of the MCP Yandex Tracker server. Focus EXCLUSIVELY on conformance with the real Yandex Tracker REST API.
${PROJECT_CONTEXT}
The PR adds an HTTP client method:
  GET v3/issues/{issue_id}/attachments/{attachment_id}/{file_name}  -> returns raw bytes; on 404 raises IssueNotFound(issue_id).

Investigate using web search/fetch of the official Yandex Tracker API docs (yandex.cloud / yandex.ru tracker API "attachments", "download file", "скачать файл вложения") AND by reading the repo:
1. Is the download endpoint path correct? Is the trailing {file_name} segment actually required by the API, and what exactly must it be (original filename? any value?)? Cite the doc.
2. URL encoding: file_name (and issue_id) are interpolated directly into the request path. How does aiohttp+yarl handle special chars/spaces/cyrillic/slashes in file_name when passed as a str path with base_url set? Could a filename with spaces or unicode break the request or hit the wrong URL? Could a filename containing '/' or '..' alter the request path (SSRF-ish / wrong endpoint)? Read client.py to confirm how the session is built.
3. Error semantics: a 404 here can mean issue-not-found OR attachment-not-found. Is mapping every 404 to IssueNotFound(issue_id) correct/misleading? What other status codes (403, 401, 410, temporary/external attachments) matter? Compare with how the existing issue_get_attachments handles errors.
4. Response handling: is reading the whole body as bytes appropriate? Does the API stream large files? Is there a separate thumbnails endpoint or temporary-attachment endpoint that the tool ignores but should be documented?
5. Does the returned mime_type (guessed from filename via mimetypes) match what the API already provides (IssueAttachment.mimetype / Content-Type response header)? Is guessing the right choice vs using the authoritative source?

To use web tools, call ToolSearch with query "select:WebSearch,WebFetch" first, then use them. Verify claims against primary docs; quote the exact passage/URL in evidence. Report concrete findings only.`,
  },
  {
    key: 'standards-conventions',
    prompt: `You are reviewing PR #33 of the MCP Yandex Tracker server. Focus on conformance to THIS project's standards and conventions (NOT generic style).
${PROJECT_CONTEXT}
Examine the diff (${DIFF}) and the surrounding repo:
1. Tool naming: the tool is 'issue_download_attachment' while every other read tool is 'issue_get_*'. Is this inconsistent? Note that sibling PR #34 adds 'issue_add_attachment'. What naming would be consistent? Also check the PR body/README/manifest for any naming mismatch (the body text vs the actual @mcp.tool function name vs README vs manifest.json).
2. Model placement/inheritance: DownloadedIssueAttachment subclasses BaseModel, not BaseTrackerEntity. CLAUDE.md says Tracker-entity models inherit BaseTrackerEntity. Is this a real violation or a justified exception (it's a local-only synthetic result)? Check what other non-entity response models in the repo do.
3. Layering: does the new code respect the protocol -> client -> caching -> tool layering? Is filesystem I/O (save_issue_attachment_file) correctly placed in mcp/utils.py and the tool layer, rather than in the HTTP client? Is the caching wrapper pass-through placed/correct (no @cached on binary, but is it inside the cached class consistently with other pass-throughs)?
4. Import ordering / formatting: inspect the new imports in mcp/utils.py ('from pathlib import Path' then 'import re'), issue_read.py, and tests/mcp/tools/test_issue_read_tools.py ('from unittest.mock import AsyncMock' then blank line then 'from pathlib import Path'). Would ruff/isort reorder these? Read pyproject.toml / ruff config to determine the configured isort behavior (force_sort_within_sections etc.). This is evidence that 'task' may not have been run.
5. Docs sync: are README.md, README_ru.md, manifest.json all consistent with the actual tool name, params, and behavior? CLAUDE.md requires updating all three.
6. Test conventions per CLAUDE.md: are new tests in the right locations, using the prescribed fixtures/patterns (AsyncMock spec=, aioresponses, parametrize, model_construct)? Is the required server-creation test list updated (READ_ONLY_TOOL_NAMES count 24->25)? Is there a queue-restriction test (client_session_with_limits) for the new issue-accessing tool as CLAUDE.md requires?

Read the actual files (pyproject.toml, conftest.py, existing tools) to ground each claim. Report concrete findings.`,
  },
  {
    key: 'security-safety',
    prompt: `You are reviewing PR #33 of the MCP Yandex Tracker server. Focus EXCLUSIVELY on security and safety of writing downloaded bytes to the local filesystem and fetching remote content.
${PROJECT_CONTEXT}
Key code: mcp/utils.py save_issue_attachment_file() and the issue_download_attachment tool + client method. Read them in the diff (${DIFF}) and repo.
Analyze:
1. Arbitrary filesystem write: save_directory is an unrestricted absolute/relative path, expanduser().resolve() + mkdir(parents=True, exist_ok=True), then write_bytes. The MCP server can thus create dirs and write files ANYWHERE the process user can write (overwrite ~/.ssh/authorized_keys-adjacent, config files, etc.) at the request of an LLM/client. Is there any allowlist/sandbox/base-dir confinement? Should there be? How severe given this is a server with server-side creds?
2. Path traversal: issue_id/attachment_id are regex-validated; file_name uses Path(file_name).name for the local name (good). But is there any residual traversal via save_directory itself, or via symlinks in the target dir? Does resolve() before mkdir help or hurt?
3. File overwrite: local_path.write_bytes silently overwrites an existing file of the same {issue_id}-{attachment_id}.ext. Data-loss / clobber risk? TOCTOU?
4. Memory/DoS: client reads the ENTIRE attachment into memory (await response.read()) then write_bytes the whole buffer. No size cap, no streaming. A large attachment can OOM the server. Is there any max-size guard? Compare to whether the project sets limits elsewhere.
5. Blocking I/O on the event loop: write_bytes and mkdir are synchronous blocking calls inside an async tool, and the whole file is buffered in RAM. Does the project use async file I/O (aiofiles / run_in_executor) anywhere? Is blocking the loop a real concern here?
6. file_name in the OUTBOUND URL is attacker/LLM-influenced and not sanitized for the HTTP request (only for the local filename). Could a crafted file_name cause request smuggling / hitting a different path / SSRF within api.tracker.yandex.net? (coordinate-level note; the api-conformance reviewer also looks at encoding.)
7. Information returned: local_path is an absolute server path returned to the client/LLM — minor info disclosure?

Read the real code. For each finding give a concrete exploit/impact scenario and a fix. Report concrete findings.`,
  },
  {
    key: 'correctness-design',
    prompt: `You are reviewing PR #33 of the MCP Yandex Tracker server. Focus on correctness bugs and design quality (excluding pure security and pure API-doc-conformance, which other reviewers cover).
${PROJECT_CONTEXT}
Read the diff (${DIFF}) and repo. Analyze:
1. mime_type: tool guesses mime from filename via mimetypes.guess_type and falls back to application/octet-stream. But IssueAttachment from issue_get_attachments already carries an authoritative 'mimetype'. Re-guessing can disagree with reality (e.g. extensionless files, .gz returns application/gzip not the archive content). Design smell?
2. Local filename design: file is saved as '{issue_id}-{attachment_id}{suffix}', DISCARDING the human-readable original name. Two different attachments with same id across issues won't collide, but the user loses the real filename and multi-suffix files (archive.tar.gz) keep only '.gz'. Is 'name' returned (basename of input) consistent with what's actually on disk (which uses the id-based name)? The returned 'name' (image.png) != actual file stem (TEST-1-7699.png) — confusing contract?
3. Redundant/awkward parameters: the tool requires file_name as an explicit param (used for the URL AND mime guess AND suffix) plus attachment_id. The user must first call issue_get_attachments to get both. Could attachment_id alone suffice (does the API need the name)? Coordinate with api reviewer but assess the ergonomics/contract.
4. Path(safe_name).suffix when file_name has no extension -> '' -> file written with NO extension; is that intended/documented?
5. The tool computes safe_name = Path(file_name).name and mime in the tool, while save_issue_attachment_file ALSO recomputes Path(file_name).name internally — duplicated logic, two sources of truth. Refactor smell?
6. Return type DownloadedIssueAttachment lacks the original attachment_id/issue_id — is the result self-describing enough?
7. Any error path gaps: what if save_directory is a path to an existing FILE (not dir)? mkdir raises; is the error surfaced sanely to the MCP client? What if disk is full / permission denied?
8. Caching layer: pass-through is fine, but is the method correctly NOT cached, and is there any inconsistency with how the class is structured?

Read real code, reason about actual execution. Report concrete findings with severity.`,
  },
  {
    key: 'test-coverage',
    prompt: `You are reviewing PR #33 of the MCP Yandex Tracker server. Focus on test coverage gaps and blind spots.
${PROJECT_CONTEXT}
Read the diff (${DIFF}) and the new/existing tests. Identify what is NOT tested but should be, per the project's own CLAUDE.md testing requirements:
1. Missing queue-restriction test: CLAUDE.md requires testing tools that access issues with client_session_with_limits. Is there one for issue_download_attachment? (check tests/mcp/tools/test_issue_read_tools.py and conftest).
2. HTTP-layer edge cases untested: filename with spaces/cyrillic/url-special chars (encoding), large body, non-404 errors (403/500), empty body.
3. save_issue_attachment_file: overwrite-existing-file behavior, save_directory pointing at an existing file, '~' expansion, nested dir creation, suffix edge cases beyond the 3 covered.
4. The mime_type guessing path: extensionless -> application/octet-stream fallback is asserted? unknown extension?
5. Tool-layer: only the happy path is tested; is the access-denied path / error propagation tested?
6. Are the assertions strong (exact equality) or loose? Any test asserting on resolve() that could be platform-fragile (e.g. macOS /private symlink, Windows paths)?
7. Is the parametrize/fixture usage compliant with CLAUDE.md (no loops, model_construct, type hints on fixtures)?

For each gap, state the specific missing test and why it matters. Report concrete findings.`,
  },
]

// Run the dimension finders + the real tooling run in parallel as one barrier-free fan-out.
const reviewThunks = finders.map((f) => () =>
  agent(f.prompt, { label: `find:${f.key}`, phase: 'Review', schema: FINDINGS_SCHEMA, effort: 'high' })
    .then((r) => ({ key: f.key, findings: (r && r.findings) || [] }))
)

// Tooling agent: actually run the checks on the PR branch in an isolated worktree.
reviewThunks.push(() =>
  agent(
    `You are verifying PR #33 of the MCP Yandex Tracker server by ACTUALLY RUNNING the project checks against the PR code. You are in an isolated git worktree.
Steps:
1. Fetch and check out the PR branch: run 'git fetch origin pull/33/head:pr33-review' then 'git checkout pr33-review' (or use 'gh pr checkout 33'). If that fails, fetch the remote ref and check it out by SHA.
2. Install deps if needed: 'uv sync' (allow time).
3. Run the FULL gate exactly as the project defines it. Inspect Taskfile.yml / pyproject.toml for the real commands, then run them individually so you can attribute failures:
   - ruff format --check (or 'task format' in check mode) and ruff check  -> capture lint/format violations (especially import ordering in mcp/utils.py, issue_read.py, tests/mcp/tools/test_issue_read_tools.py).
   - the type checker (mypy or pyright as configured) -> capture type errors on the new code.
   - pytest (the new tests) -> capture pass/fail; note any platform-fragile assertions.
4. Report each concrete failure (command + exact error output) as a finding with category 'tooling'. If everything passes cleanly, report a single informational finding saying the gate passes, with the exact commands run and their summarized output as evidence.
Be precise: quote real command output in 'evidence'. Do NOT speculate — only report what the tools actually output.`,
    { label: 'find:tooling-run', phase: 'Review', schema: FINDINGS_SCHEMA, effort: 'high', isolation: 'worktree' }
  ).then((r) => ({ key: 'tooling-run', findings: (r && r.findings) || [] }))
)

const reviewResults = (await parallel(reviewThunks)).filter(Boolean)

// Flatten + tag with source dimension.
const allFindings = reviewResults.flatMap((r) =>
  r.findings.map((f, i) => ({ ...f, source: r.key, fid: `${r.key}#${i + 1}` }))
)

log(`Collected ${allFindings.length} raw findings across ${reviewResults.length} reviewers. Verifying...`)

phase('Verify')

// Adversarially verify each finding independently. Default to skepticism.
const verified = await parallel(
  allFindings.map((f) => () =>
    agent(
      `You are an adversarial verifier for a code review of PR #33 (MCP Yandex Tracker). Your job is to REFUTE the following finding unless the code/docs clearly support it. Default to 'refuted' or 'uncertain' if you cannot independently confirm it.
${PROJECT_CONTEXT}
FINDING (from reviewer '${f.source}'):
- title: ${f.title}
- severity: ${f.severity}
- category: ${f.category}
- location: ${f.location}
- description: ${f.description}
- evidence claimed: ${f.evidence}
- recommendation: ${f.recommendation}

Independently verify by reading the ACTUAL repo files referenced (and the diff at ${DIFF}), and for any API/doc claim, verify against primary Yandex Tracker docs (use ToolSearch "select:WebSearch,WebFetch" then those tools). Check: does the code really do what the finding claims? Is the cited evidence accurate? Is the severity proportionate? Could the finding be a false positive (e.g. handled elsewhere, intended behavior, or a non-issue in this context)?
Return your verdict. If confirmed, set adjusted_severity to the proportionate level; if the finding is wrong, set verdict=refuted and adjusted_severity=invalid.`,
      { label: `verify:${f.fid}`, phase: 'Verify', schema: VERDICT_SCHEMA, effort: 'high' }
    ).then((v) => ({ ...f, verdict: v }))
  )
)

const out = verified.filter(Boolean).map((f) => ({
  fid: f.fid,
  source: f.source,
  title: f.title,
  category: f.category,
  location: f.location,
  reported_severity: f.severity,
  confidence: f.confidence,
  description: f.description,
  evidence: f.evidence,
  recommendation: f.recommendation,
  verdict: f.verdict?.verdict || 'uncertain',
  adjusted_severity: f.verdict?.adjusted_severity || f.severity,
  verify_reasoning: f.verdict?.reasoning || '',
}))

return {
  total_raw: allFindings.length,
  confirmed: out.filter((f) => f.verdict === 'confirmed'),
  uncertain: out.filter((f) => f.verdict === 'uncertain'),
  refuted: out.filter((f) => f.verdict === 'refuted'),
}

